1	type BoundingBox = { minRow: number; maxRow: number; minCol: number; maxCol: number } | null;
2	
3	const findLiveCellBounds = (grid: boolean[][]): BoundingBox => {
4	  let minRow = grid.length, maxRow = -1, minCol = grid[0].length, maxCol = -1;
5	  for (let r = 0; r < grid.length; r++) {
6	    for (let c = 0; c < grid[r].length; c++) {
7	      if (grid[r][c]) {
8	        if (r < minRow) minRow = r;
9	        if (r > maxRow) maxRow = r;
10	        if (c < minCol) minCol = c;
11	        if (c > maxCol) maxCol = c;
12	      }
13	    }
14	  }
15	  return maxRow === -1 ? null : { minRow, maxRow, minCol, maxCol };
16	};
17	
18	export function nextGeneration(grid: boolean[][]): boolean[][] {
19	  if (grid.length === 0) return [];
20	
21	  const rows = grid.length;
22	  const cols = grid[0].length;
23	
24	  const countNeighbors = (r: number, c: number): number => {
25	    let count = 0;
26	    for (let dr = -1; dr <= 1; dr++) {
27	      for (let dc = -1; dc <= 1; dc++) {
28	        if (dr === 0 && dc === 0) continue;
29	        const nr = r + dr;
30	        const nc = c + dc;
31	        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && grid[nr][nc]) {
32	          count++;
33	        }
34	      }
35	    }
36	    return count;
37	  };
38	
39	  const next: boolean[][] = [];
40	  for (let r = 0; r < rows; r++) {
41	    const row: boolean[] = [];
42	    for (let c = 0; c < cols; c++) {
43	      const neighbors = countNeighbors(r, c);
44	      const alive = grid[r][c];
45	      row.push(alive ? neighbors === 2 || neighbors === 3 : neighbors === 3);
46	    }
47	    next.push(row);
48	  }
49	
50	  const bounds = findLiveCellBounds(next);
51	  if (bounds === null) return [];
52	
53	  const { minRow, maxRow, minCol, maxCol } = bounds;
54	  const result: boolean[][] = [];
55	  for (let r = minRow; r <= maxRow; r++) {
56	    result.push(next[r].slice(minCol, maxCol + 1));
57	  }
58	  return result;
59	}
