it("should kill a live cell with more than 3 live neighbors", () => {
  // A live cell with 4 live neighbors (overpopulation) dies
  // Use a cross pattern: center has 4 live neighbors
  //   false true  false
  //   true  true  true
  //   false true  false
  // Center has 4 neighbors and dies; corner cells are dead; edge cells each have 3 live neighbors and spawn
  // Result after next gen: only the 4 dead edge cells come alive (3 neighbors each), center dies
  // The center cell specifically should be dead
  const result = nextGeneration([
    [false, true, false],
    [true, true, true],
    [false, true, false],
  ]);
  // Center cell (was live, had 4 neighbors) must be dead in the result
  // The result grid is trimmed, so we need to check the center position
  // The new grid: corners come alive (3 neighbors), center dies (4 neighbors), edges stay alive (2 neighbors)
  // Result: [true, true, true], [true, false, true], [true, true, true]
  expect(result).toEqual([
    [true, true, true],
    [true, false, true],
    [true, true, true],
  ]);
});

